-- Case 022: ASOF JOIN, RESAMPLE, window interpolation, and device time-series cleanup
WITH filtered AS(SELECT device_id,reading_at,metric_name,TRY_TO_DOUBLE(metric_value) AS metric_value,metadata FROM IOT.SENSOR_READING WHERE reading_at >= DATEADD( 'hour',-24,CURRENT_TIMESTAMP()) AND metric_name IN( 'temperature', 'humidity', 'pressure')),sampled AS(SELECT device_id,reading_at,metric_name,metric_value,INTERPOLATE_FFILL(metric_value) OVER(PARTITION BY device_id,metric_name ORDER BY reading_at) AS metric_value_filled FROM filtered RESAMPLE(USING reading_at INCREMENT BY INTERVAL '5 minutes' PARTITION BY device_id,metric_name)),calibrated AS(SELECT s.device_id,s.reading_at,s.metric_name,s.metric_value_filled,c.calibration_id,c.offset_value,c.scale_value,s.metric_value_filled * COALESCE(c.scale_value,1) + COALESCE(c.offset_value,0) AS calibrated_value FROM sampled AS s ASOF JOIN IOT.DEVICE_CALIBRATION AS c MATCH_CONDITION(s.reading_at >= c.calibrated_at) ON s.device_id = c.device_id AND s.metric_name = c.metric_name) SELECT device_id,DATE_TRUNC( 'hour',reading_at) AS reading_hour,metric_name,AVG(calibrated_value) AS avg_calibrated_value,MIN(calibrated_value) AS min_calibrated_value,MAX(calibrated_value) AS max_calibrated_value,COUNT(*) AS sample_count,ANY_VALUE(calibration_id) AS sample_calibration_id FROM calibrated GROUP BY device_id,reading_hour,metric_name ORDER BY device_id,reading_hour,metric_name;
